#!/usr/bin/env python

import os
import sys
import subprocess
import time
import shutil

def validate_directory(directory):
    if not os.path.exists(directory):
        print("Error: Directory does not exist: {}".format(directory))
        sys.exit(1)
    if not os.path.isdir(directory):
        print("Error: Path is not a directory: {}".format(directory))
        sys.exit(1)
    abs_path = os.path.abspath(directory)
    return abs_path

def validate_format(format_type):
    valid_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if format_type not in valid_formats:
        print("Error: Invalid format. Supported formats: {}".format(', '.join(valid_formats)))
        sys.exit(1)
    return format_type

def check_command_exists(command):
    return shutil.which(command) is not None

def create_backup_name(directory, format_type):
    timestamp = time.strftime("%Y%m%d_%H%M%S")
    dir_name = os.path.basename(directory.rstrip(os.sep))
    if format_type == 'tar.gz':
        extension = '.tar.gz'
    elif format_type == 'tar.bz2':
        extension = '.tar.bz2'
    elif format_type == 'zip':
        extension = '.zip'
    elif format_type == '7z':
        extension = '.7z'
    else:
        extension = '.tar.gz'
    
    backup_name = "backup_{}_{}{}".format(dir_name, timestamp, extension)
    return backup_name

def create_tar_gz_backup(directory, output_file):
    if not check_command_exists('tar'):
        print("Error: tar command not found")
        sys.exit(1)
    
    parent_dir = os.path.dirname(directory)
    dir_name = os.path.basename(directory)
    
    tar_path = shutil.which('tar')
    args = [tar_path, '-czf', output_file, '-C', parent_dir, dir_name]
    
    try:
        subprocess.check_call(args)
        print("Backup created successfully: {}".format(output_file))
    except subprocess.CalledProcessError as e:
        print("Error creating tar.gz backup: {}".format(e))
        sys.exit(1)

def create_tar_bz2_backup(directory, output_file):
    if not check_command_exists('tar'):
        print("Error: tar command not found")
        sys.exit(1)
    
    parent_dir = os.path.dirname(directory)
    dir_name = os.path.basename(directory)
    
    tar_path = shutil.which('tar')
    args = [tar_path, '-cjf', output_file, '-C', parent_dir, dir_name]
    
    try:
        subprocess.check_call(args)
        print("Backup created successfully: {}".format(output_file))
    except subprocess.CalledProcessError as e:
        print("Error creating tar.bz2 backup: {}".format(e))
        sys.exit(1)

def create_zip_backup(directory, output_file):
    if not check_command_exists('zip'):
        print("Error: zip command not found")
        sys.exit(1)
    
    parent_dir = os.path.dirname(directory)
    dir_name = os.path.basename(directory)
    
    zip_path = shutil.which('zip')
    args = [zip_path, '-r', output_file, dir_name]
    
    original_dir = os.getcwd()
    try:
        os.chdir(parent_dir)
        subprocess.check_call(args)
        print("Backup created successfully: {}".format(output_file))
    except subprocess.CalledProcessError as e:
        print("Error creating zip backup: {}".format(e))
        sys.exit(1)
    finally:
        os.chdir(original_dir)

def create_7z_backup(directory, output_file):
    if not check_command_exists('7z'):
        if not check_command_exists('7za'):
            print("Error: 7z command not found")
            sys.exit(1)
        else:
            sevenz_path = shutil.which('7za')
    else:
        sevenz_path = shutil.which('7z')
    
    args = [sevenz_path, 'a', '-t7z', output_file, directory]
    
    try:
        subprocess.check_call(args)
        print("Backup created successfully: {}".format(output_file))
    except subprocess.CalledProcessError as e:
        print("Error creating 7z backup: {}".format(e))
        sys.exit(1)

def main():
    if len(sys.argv) != 3:
        print("Usage: {} <directory_path> <format>".format(sys.argv[0]))
        print("Supported formats: tar.gz, tar.bz2, zip, 7z")
        sys.exit(1)
    
    directory = sys.argv[1]
    format_type = sys.argv[2]
    
    directory = validate_directory(directory)
    format_type = validate_format(format_type)
    
    backup_name = create_backup_name(directory, format_type)
    output_file = os.path.abspath(backup_name)
    
    print("Creating backup of: {}".format(directory))
    print("Format: {}".format(format_type))
    print("Output: {}".format(output_file))
    
    if format_type == 'tar.gz':
        create_tar_gz_backup(directory, output_file)
    elif format_type == 'tar.bz2':
        create_tar_bz2_backup(directory, output_file)
    elif format_type == 'zip':
        create_zip_backup(directory, output_file)
    elif format_type == '7z':
        create_7z_backup(directory, output_file)

if __name__ == '__main__':
    main()